# ── Generic verbs requiring deontic co-occurrence ────────────────────
# These verbs are valid institutional AIMs but too generic to confirm
# AIM>=1 on their own. They only count if a deontic/modal marker is also
# present in the sentence (shall, must, may, debe, deberá, etc.)
GENERIC_VERBS_REQUIRING_DEONTIC: set = {
    'ser', 'tener', 'estar', 'haber', 'hacer', 'dar', 'poder', 'poner', 'pasar',
    'quedar', 'dejar', 'contar', 'encontrar', 'conocer',
    'be', 'have', 'is', 'are', 'has', 'was', 'were', 'been', 'do', 'does',
    'make', 'take', 'get', 'give', 'set', 'put', 'consist',
    # Spanish descriptive verbs often confused with institutional
    'constar', 'consta', 'tiene', 'hallarse', 'saber', 'durar', 'contar', 'permanecer',
    'radicar', 'figurar', 'integrar', 'comprender', 'abarcar',
}

# ── Utility functions ────────────────────────────────────────────
def sentence_has_institutional_verb(sentence: str) -> bool:
    """Return True if sentence contains any institutional verb form."""
    s = sentence.lower()
    return any(v in s for v in INSTITUTIONAL_VERBS)


def get_matching_verbs(sentence: str) -> List[str]:
    """Return all canonical verbs found in the sentence."""
    s = sentence.lower()
    found = []
    for canon, meta in VERB_META.items():
        # check canonical form
        if canon in s:
            found.append(canon)
    return found


def has_deontic_marker(sentence: str) -> bool:
    """Return True if sentence contains a deontic/modal pattern."""
    s = sentence.lower()
    return any(d in s for d in DEONTIC_PATTERNS)


def aim_veto_score(sentence: str) -> float:
    """
    Compute a confidence score that a sentence is AIM>=1.
    Returns 0.0-1.0.

    Recommended threshold: 0.75

    Scoring logic:
      - Tier A verb (non-generic):              0.90  -> above threshold alone
      - Tier B/manual verb (non-generic):       0.75  -> at threshold alone
      - Tier B/manual verb + deontic marker:    0.85  -> clearly above threshold
      - Generic verb (ser/tener/be/have/etc):
          + deontic marker:                     0.85  -> above threshold
          alone:                                0.00  -> not enough signal
      - Deontic marker alone (no verb match):   0.60  -> below threshold (weak signal)
      - No match:                               0.00  -> likely AIM=0

    Use: if aim_veto_score(sentence) >= 0.75 -> confirm AIM>=1 (veto AIM=0)
    """
    s = sentence.lower()
    score = 0.0
    deontic = has_deontic_marker(sentence)

    import re as _re
    def _matches(verb: str, text: str) -> bool:
        # Use word-boundary matching for short verbs (<=6 chars) to avoid substrings
        if len(verb) <= 6:
            pattern = r'(?<![a-záéíóúüñ])' + _re.escape(verb) + r'(?![a-záéíóúüñ])'
            return bool(_re.search(pattern, text))
        return verb in text

    for canon, meta in VERB_META.items():
        if _matches(canon, s):
            tier = meta.get("tier", "B")
            if canon in GENERIC_VERBS_REQUIRING_DEONTIC:
                if deontic:
                    score = max(score, 0.85)
            else:
                if tier == "A":
                    score = max(score, 0.90)
                else:  # Tier B or manual
                    boosted = 0.85 if deontic else 0.75
                    score = max(score, boosted)

    if deontic and score == 0.0:
        score = 0.60  # deontic alone: weak positive signal

    return round(min(score, 1.0), 2)


def lookup_verb_type(verb: str, language: str = "es") -> str | None:
    """Return institutional grammar type for a verb, if present.

    The language parameter is accepted for compatibility; the lexicon is
    bilingual (ES+EN merged).
    """
    v = verb.lower().strip()
    if v in VERB_META:
        return VERB_META[v].get("type")
    return None
